CREATE TABLE `acXaccount` (
  `ac_acid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Account ID',
  `ac_bkid` bigint NOT NULL COMMENT 'Booking ID',
  `ac_usid` varchar(15) NOT NULL COMMENT 'Customer User ID',
  `ac_totamt` decimal(15,2) DEFAULT '0.00' COMMENT 'Total Amount',
  `ac_rcvdamt` decimal(15,2) DEFAULT '0.00' COMMENT 'Received Amount',
  `ac_pendamt` decimal(15,2) DEFAULT '0.00' COMMENT 'Pending Amount',
  `ac_duedt` datetime DEFAULT NULL COMMENT 'Due Date',
  `ac_fyear` varchar(10) DEFAULT NULL COMMENT 'Financial Year',
  `ac_status` varchar(15) DEFAULT 'PENDING' COMMENT 'Account Status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  PRIMARY KEY (`ac_acid`),
  KEY `ac_bkid` (`ac_bkid`),
  KEY `ac_usid` (`ac_usid`),
  CONSTRAINT `acxaccount_ibfk_17` FOREIGN KEY (`ac_bkid`) REFERENCES `bkXbooking` (`bk_bkid`) ON UPDATE CASCADE,
  CONSTRAINT `acxaccount_ibfk_18` FOREIGN KEY (`ac_usid`) REFERENCES `usXuser` (`us_usid`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
