--
-- Table structure for table `blXbilling`
--

DROP TABLE IF EXISTS `blXbilling`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `blXbilling` (
  `bl_id` int NOT NULL AUTO_INCREMENT,
  `bl_entry_no` varchar(30) NOT NULL,
  `bl_bill_no` varchar(30) DEFAULT NULL,
  `bl_sub_bill_no` varchar(30) DEFAULT NULL,
  `bl_booking_id` bigint NOT NULL,
  `bl_billing_date` date NOT NULL COMMENT 'Used for biling date',
  `bl_journey_date` date NOT NULL,
  `bl_customer_name` varchar(150) NOT NULL,
  `bl_customer_phone` varchar(15) NOT NULL,
  `bl_station_boy` varchar(100) DEFAULT NULL,
  `bl_from_station` varchar(50) DEFAULT NULL,
  `bl_to_station` varchar(50) DEFAULT NULL,
  `bl_train_no` varchar(10) DEFAULT NULL,
  `bl_class` varchar(10) DEFAULT NULL,
  `bl_pnr` varchar(15) DEFAULT NULL,
  `bl_seats_reserved` varchar(50) DEFAULT NULL,
  `bl_railway_fare` decimal(10,2) DEFAULT '0.00',
  `bl_sb_incentive` decimal(10,2) DEFAULT '0.00',
  `bl_gst` decimal(10,2) DEFAULT '0.00',
  `bl_misc_charges` decimal(10,2) DEFAULT '0.00',
  `bl_platform_fee` decimal(10,2) DEFAULT '0.00',
  `bl_service_charge` decimal(10,2) DEFAULT '0.00',
  `bl_delivery_charge` decimal(10,2) DEFAULT '0.00',
  `bl_cancellation_charge` decimal(10,2) DEFAULT '0.00',
  `bl_surcharge` decimal(10,2) DEFAULT '0.00',
  `bl_discount` decimal(10,2) DEFAULT '0.00',
  `bl_gst_type` enum('INCLUSIVE','EXCLUSIVE','C') DEFAULT 'EXCLUSIVE',
  `bl_total_amount` decimal(12,2) NOT NULL,
  `bl_is_split` tinyint(1) DEFAULT '0',
  `bl_parent_bill_id` int DEFAULT NULL,
  `bl_created_by` int DEFAULT NULL,
  `bl_created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `entered_by` int DEFAULT NULL,
  `entered_on` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` int DEFAULT NULL,
  `modified_on` timestamp NULL DEFAULT NULL,
  `closed_by` int DEFAULT NULL,
  `closed_on` timestamp NULL DEFAULT NULL,
  `status` enum('OPEN','CLOSED','CANCELLED','DRAFT','FINAL','PAID','PARTIAL','CNF','CAN','CONFIRMED','PENDING') DEFAULT 'CNF',
  `bl_railway_cancellation_charge` decimal(10,2) DEFAULT '0.00' COMMENT 'Railway Cancellation Charge',
  `bl_status` enum('OPEN','CLOSED','CANCELLED','DRAFT','FINAL','PAID','PARTIAL','CNF','CAN','CONFIRMED','PENDING') DEFAULT 'CNF',
  `is_cancelled` tinyint(1) DEFAULT '0' COMMENT 'Flag indicating if bill is cancelled',
  `cancelled_on` datetime DEFAULT NULL COMMENT 'Timestamp when bill was cancelled',
  `cancelled_by` varchar(15) DEFAULT NULL COMMENT 'User ID who cancelled the bill',
  `cancellation_date` date DEFAULT NULL COMMENT 'Effective date of cancellation',
  `total_cancel_charges` decimal(10,2) DEFAULT '0.00' COMMENT 'Total cancellation charges (railway + agent)',
