DROP TABLE IF EXISTS `contra_entries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contra_entries` (
  `contra_id` int NOT NULL AUTO_INCREMENT,
  `voucher_no` varchar(20) NOT NULL,
  `entry_date` date NOT NULL,
  `ledger_from` varchar(150) NOT NULL,
  `ledger_to` varchar(150) NOT NULL,
  `amount` decimal(12,2) NOT NULL,
  `cheque_draft_no` varchar(50) DEFAULT NULL,
  `narration` text,
  `total_debit` decimal(12,2) NOT NULL DEFAULT '0.00',
  `total_credit` decimal(12,2) NOT NULL DEFAULT '0.00',
  `balance_check` tinyint(1) NOT NULL DEFAULT '0',
  `financial_year` varchar(10) NOT NULL,
  `accounting_period` varchar(7) NOT NULL,
  `locked` tinyint(1) NOT NULL DEFAULT '0',
  `created_by` int NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` int DEFAULT NULL,
  `modified_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`contra_id`),
  UNIQUE KEY `voucher_no` (`voucher_no`),
  KEY `idx_voucher_no` (`voucher_no`),
  KEY `idx_entry_date` (`entry_date`),
  KEY `idx_financial_year` (`financial_year`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_locked` (`locked`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
