  `ct_entry_no` varchar(20) NOT NULL COMMENT 'Auto-generated entry number',
  `ct_date` date NOT NULL COMMENT 'Contra date',
  `ct_from_account` varchar(100) NOT NULL COMMENT 'Source account',
  `ct_to_account` varchar(100) NOT NULL COMMENT 'Destination account',
  `ct_amount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Contra amount',
  `ct_narration` varchar(200) DEFAULT NULL COMMENT 'Narration/description',
  `ct_ref_number` varchar(50) DEFAULT NULL COMMENT 'Reference number',
  `ct_created_by` varchar(15) NOT NULL COMMENT 'User ID who created the contra entry',
  `ct_status` enum('Active','Inactive','Deleted') NOT NULL DEFAULT 'Active' COMMENT 'Contra status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`ct_ctid`),
  UNIQUE KEY `ct_entry_no` (`ct_entry_no`),
  KEY `idx_ct_entry_no` (`ct_entry_no`),
  KEY `idx_ct_date` (`ct_date`),
  KEY `idx_ct_from_account` (`ct_from_account`),
  KEY `idx_ct_to_account` (`ct_to_account`),
  KEY `idx_ct_created_by` (`ct_created_by`)
) ENGINE=InnoDB AUTO_INCREMENT=601 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
