CREATE TABLE `emXemployee` (
  `em_usid` varchar(15) NOT NULL COMMENT 'Employee User ID',
  `em_empno` varchar(10) NOT NULL COMMENT 'Employee Number',
  `em_dept` varchar(20) NOT NULL COMMENT 'Employee Department',
  `em_salary` decimal(12,2) DEFAULT NULL COMMENT 'Employee Salary',
  `em_joindt` datetime NOT NULL COMMENT 'Join Date',
  `em_manager` varchar(15) DEFAULT NULL COMMENT 'Manager User ID',
  `em_status` varchar(15) DEFAULT 'ACTIVE' COMMENT 'Employee Status',
  `em_address` varchar(100) DEFAULT NULL COMMENT 'Address',
  `em_city` varchar(30) DEFAULT NULL COMMENT 'City',
  `em_state` varchar(30) DEFAULT NULL COMMENT 'State',
  `em_pincode` varchar(10) DEFAULT NULL COMMENT 'Pincode',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  `cdtm` datetime DEFAULT NULL COMMENT 'Closed Date Time',
  `cby` varchar(15) DEFAULT NULL COMMENT 'Closed By',
  `em_photo` varchar(255) DEFAULT NULL COMMENT 'Employee Photo Path',
  PRIMARY KEY (`em_usid`),
  UNIQUE KEY `em_empno` (`em_empno`),
  UNIQUE KEY `em_empno_2` (`em_empno`),
  UNIQUE KEY `em_empno_3` (`em_empno`),
  UNIQUE KEY `em_empno_4` (`em_empno`),
