  UNIQUE KEY `em_empno_8` (`em_empno`),
  UNIQUE KEY `em_empno_9` (`em_empno`),
  UNIQUE KEY `em_empno_10` (`em_empno`),
  UNIQUE KEY `em_empno_11` (`em_empno`),
  UNIQUE KEY `em_empno_12` (`em_empno`),
  UNIQUE KEY `em_empno_13` (`em_empno`),
  UNIQUE KEY `em_empno_14` (`em_empno`),
  UNIQUE KEY `em_empno_15` (`em_empno`),
  UNIQUE KEY `em_empno_16` (`em_empno`),
  UNIQUE KEY `em_empno_17` (`em_empno`),
  UNIQUE KEY `em_empno_18` (`em_empno`),
  UNIQUE KEY `em_empno_19` (`em_empno`),
  UNIQUE KEY `em_empno_20` (`em_empno`),
  UNIQUE KEY `em_empno_21` (`em_empno`),
  UNIQUE KEY `em_empno_22` (`em_empno`),
  UNIQUE KEY `em_empno_23` (`em_empno`),
  UNIQUE KEY `em_empno_24` (`em_empno`),
  KEY `em_manager` (`em_manager`),
  CONSTRAINT `emxemployee_ibfk_1` FOREIGN KEY (`em_usid`) REFERENCES `usXuser` (`us_usid`) ON UPDATE CASCADE,
  CONSTRAINT `emxemployee_ibfk_2` FOREIGN KEY (`em_manager`) REFERENCES `emXemployee` (`em_usid`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
