CREATE TABLE `jeXjournal` (
  `je_jeid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Journal Entry ID',
  `je_entry_no` varchar(20) NOT NULL COMMENT 'Auto-generated entry number',
  `je_date` date NOT NULL COMMENT 'Journal entry date',
  `je_account` varchar(100) NOT NULL COMMENT 'Account name',
  `je_entry_type` enum('Debit','Credit') NOT NULL COMMENT 'Entry type',
  `je_amount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Journal entry amount',
  `je_narration` varchar(200) DEFAULT NULL COMMENT 'Narration/description',
  `je_ref_number` varchar(50) DEFAULT NULL COMMENT 'Reference number',
  `je_voucher_type` enum('Cash','Bank','Contra','Purchase','Sales','Journal') NOT NULL DEFAULT 'Journal' COMMENT 'Voucher type',
  `je_created_by` varchar(15) NOT NULL COMMENT 'User ID who created the journal entry',
  `je_status` enum('Active','Inactive','Deleted') NOT NULL DEFAULT 'Active' COMMENT 'Journal entry status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`je_jeid`),
  UNIQUE KEY `je_entry_no` (`je_entry_no`),
  KEY `idx_je_entry_no` (`je_entry_no`),
  KEY `idx_je_date` (`je_date`),
  KEY `idx_je_account` (`je_account`),
  KEY `idx_je_entry_type` (`je_entry_type`),
  KEY `idx_je_voucher_type` (`je_voucher_type`),
  KEY `idx_je_created_by` (`je_created_by`)
) ENGINE=InnoDB AUTO_INCREMENT=601 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
