DROP TABLE IF EXISTS `paXpayalloc`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `paXpayalloc` (
  `pa_paid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Payment Allocation ID',
  `pa_ptid` bigint NOT NULL COMMENT 'Payment Transaction ID',
  `pa_pnid` bigint NOT NULL COMMENT 'PNR ID',
