  `pa_allocamt` decimal(12,2) NOT NULL COMMENT 'Allocated Amount',
  `pa_alloctn_date` datetime DEFAULT CURRENT_TIMESTAMP COMMENT 'Allocation Date',
  `pa_alloctn_type` varchar(10) DEFAULT 'MANUAL' COMMENT 'Allocation Type: AUTO (FIFO) | MANUAL (user selected)',
