--
-- Table structure for table `ptPayment`
--

DROP TABLE IF EXISTS `ptPayment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ptPayment` (
  `pt_ptid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Payment ID (Primary Key)',
  `pt_usid` varchar(15) NOT NULL COMMENT 'Customer User ID (who made the payment)',
  `pt_amount` decimal(15,2) NOT NULL COMMENT 'Total Payment Amount (immutable once posted)',
  `pt_mode` varchar(20) NOT NULL COMMENT 'Payment Mode: CASH, UPI, NEFT, RTGS, CHEQUE, CARD, BANK',
  `pt_refno` varchar(50) DEFAULT NULL COMMENT 'Reference Number (UTR / Cheque No / Transaction ID)',
  `pt_paydt` datetime NOT NULL COMMENT 'Payment Date (when payment was made)',
  `pt_rcvby` varchar(15) NOT NULL COMMENT 'Received By (User ID who recorded the payment)',
  `pt_status` varchar(15) NOT NULL DEFAULT 'RECEIVED' COMMENT 'Payment Status: RECEIVED | ADJUSTED | REFUNDED | BOUNCED',
  `pt_acct_period` varchar(7) NOT NULL COMMENT 'Accounting Period (YYYY-MM format)',
  `pt_unallocated_amt` decimal(15,2) DEFAULT '0.00' COMMENT 'Unallocated Amount (advance payment)',
  `pt_remarks` text COMMENT 'Payment Remarks',
  `pt_acid` bigint DEFAULT NULL COMMENT 'Account ID (deprecated - use customer ID directly)',
  `pt_bkid` bigint DEFAULT NULL COMMENT 'Booking ID (optional - payment can be advance)',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  PRIMARY KEY (`pt_ptid`),
  KEY `pt_acid` (`pt_acid`),
  KEY `pt_bkid` (`pt_bkid`),
  KEY `idx_pt_usid` (`pt_usid`),
  KEY `idx_pt_paydt` (`pt_paydt`),
  KEY `idx_pt_acct_period` (`pt_acct_period`),
  KEY `idx_pt_status` (`pt_status`),
  CONSTRAINT `ptpayment_ibfk_1` FOREIGN KEY (`pt_acid`) REFERENCES `acAccount` (`ac_acid`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `ptpayment_ibfk_2` FOREIGN KEY (`pt_bkid`) REFERENCES `bkXbooking` (`bk_bkid`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

