--
-- Table structure for table `pyXpayment`
--

DROP TABLE IF EXISTS `pyXpayment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pyXpayment` (
  `py_pymtid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Payment ID',
  `py_entry_no` varchar(20) NOT NULL COMMENT 'Auto-generated entry number',
  `py_date` date NOT NULL COMMENT 'Payment date',
  `py_entry_type` enum('Debit','Credit') NOT NULL COMMENT 'Entry type',
  `py_customer_name` varchar(100) DEFAULT NULL COMMENT 'Customer name',
  `py_customer_phone` varchar(15) DEFAULT NULL COMMENT 'Customer phone',
  `py_amount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Payment amount',
  `py_ref_number` varchar(50) DEFAULT NULL COMMENT 'Reference number',
  `py_bank_account` varchar(100) DEFAULT NULL COMMENT 'Bank account name',
  `py_balance` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Current balance',
  `py_total_credit` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Total credit amount',
  `py_total_debit` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Total debit amount',
  `py_created_by` varchar(15) NOT NULL COMMENT 'User ID who created the payment',
  `py_status` enum('Active','Inactive','Deleted') NOT NULL DEFAULT 'Active' COMMENT 'Payment status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `entered_by` int NOT NULL,
  `entered_on` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` int DEFAULT NULL,
  `modified_on` timestamp NULL DEFAULT NULL,
  `closed_by` int DEFAULT NULL,
  `closed_on` timestamp NULL DEFAULT NULL,
  `status` enum('OPEN','CLOSED','CANCELLED') DEFAULT 'OPEN',
  PRIMARY KEY (`py_pymtid`),
  UNIQUE KEY `py_entry_no` (`py_entry_no`),
  KEY `idx_py_entry_no` (`py_entry_no`),
  KEY `idx_py_date` (`py_date`),
  KEY `idx_py_customer_phone` (`py_customer_phone`),
  KEY `idx_py_created_by` (`py_created_by`),
  KEY `idx_py_status` (`py_status`),
  KEY `idx_py_pymtid` (`py_pymtid`),
  KEY `idx_py_customer_name` (`py_customer_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

