CREATE TABLE `rcXreceipt` (
  `rc_rcid` bigint NOT NULL AUTO_INCREMENT COMMENT 'Receipt ID',
  `rc_entry_no` varchar(20) NOT NULL COMMENT 'Auto-generated entry number',
  `rc_date` date NOT NULL COMMENT 'Receipt date',
  `rc_customer_name` varchar(100) DEFAULT NULL COMMENT 'Customer name',
  `rc_customer_phone` varchar(15) DEFAULT NULL COMMENT 'Customer phone',
  `rc_amount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT 'Receipt amount',
  `rc_payment_mode` enum('Cash','Bank','Cheque','Online') NOT NULL DEFAULT 'Cash' COMMENT 'Payment mode',
  `rc_ref_number` varchar(50) DEFAULT NULL COMMENT 'Reference number',
  `rc_bank_account` varchar(100) DEFAULT NULL COMMENT 'Bank account name',
  `rc_narration` varchar(200) DEFAULT NULL COMMENT 'Narration/description',
  `rc_created_by` varchar(15) NOT NULL COMMENT 'User ID who created the receipt',
  `rc_status` enum('Active','Inactive','Deleted') NOT NULL DEFAULT 'Active' COMMENT 'Receipt status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `entered_by` int NOT NULL,
  `entered_on` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `modified_by` int DEFAULT NULL,
  `modified_on` timestamp NULL DEFAULT NULL,
  `closed_by` int DEFAULT NULL,
  `closed_on` timestamp NULL DEFAULT NULL,
  `status` enum('OPEN','CLOSED','CANCELLED') DEFAULT 'OPEN',
  PRIMARY KEY (`rc_rcid`),
  UNIQUE KEY `rc_entry_no` (`rc_entry_no`),
  KEY `idx_rc_entry_no` (`rc_entry_no`),
  KEY `idx_rc_date` (`rc_date`),
  KEY `idx_rc_customer_phone` (`rc_customer_phone`),
  KEY `idx_rc_payment_mode` (`rc_payment_mode`),
  KEY `idx_rc_created_by` (`rc_created_by`)
) ENGINE=InnoDB AUTO_INCREMENT=601 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

