  `tr_trno` varchar(10) NOT NULL COMMENT 'Train Number',
  `tr_trname` varchar(100) NOT NULL COMMENT 'Train Name',
  `tr_fromst` varchar(10) NOT NULL COMMENT 'From Station',
  `tr_tost` varchar(10) NOT NULL COMMENT 'To Station',
  `tr_deptime` time DEFAULT NULL COMMENT 'Departure Time',
  `tr_arrtime` time DEFAULT NULL COMMENT 'Arrival Time',
  `tr_distance` decimal(8,2) DEFAULT NULL COMMENT 'Distance',
  `tr_active` tinyint(1) DEFAULT '1' COMMENT 'Active Status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime DEFAULT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  PRIMARY KEY (`tr_trid`),
  UNIQUE KEY `tr_trno` (`tr_trno`),
  UNIQUE KEY `tr_xtrain_tr_trno` (`tr_trno`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
