  `us_phone` varchar(15) NOT NULL COMMENT 'Phone Number',
  `us_aadhaar` varchar(12) DEFAULT NULL COMMENT 'Aadhaar Number',
  `us_pan` varchar(10) DEFAULT NULL COMMENT 'PAN Number',
  `us_addr1` varchar(100) DEFAULT NULL COMMENT 'Address Line 1',
  `us_addr2` varchar(100) DEFAULT NULL COMMENT 'Address Line 2',
  `us_city` varchar(50) DEFAULT NULL COMMENT 'City',
  `us_state` varchar(50) DEFAULT NULL COMMENT 'State',
  `us_pin` varchar(10) DEFAULT NULL COMMENT 'PIN Code',
  `us_usertype` varchar(10) NOT NULL COMMENT 'User Type',
  `us_roid` varchar(3) DEFAULT NULL COMMENT 'Role ID',
  `us_coid` varchar(3) DEFAULT NULL COMMENT 'Company ID',
  `us_active` tinyint DEFAULT '1' COMMENT 'Active Status',
  `edtm` datetime NOT NULL COMMENT 'Entered Date Time',
  `eby` varchar(15) NOT NULL COMMENT 'Entered By',
  `mdtm` datetime NOT NULL COMMENT 'Modified Date Time',
  `mby` varchar(15) DEFAULT NULL COMMENT 'Modified By',
  PRIMARY KEY (`us_usid`),
  UNIQUE KEY `us_email` (`us_email`),
  UNIQUE KEY `us_phone` (`us_phone`),
  UNIQUE KEY `us_user_us_email` (`us_email`),
  UNIQUE KEY `us_user_us_phone` (`us_phone`),
  UNIQUE KEY `us_email_2` (`us_email`),
  UNIQUE KEY `us_phone_2` (`us_phone`),
  UNIQUE KEY `us_aadhaar` (`us_aadhaar`),
  UNIQUE KEY `us_user_us_aadhaar` (`us_aadhaar`),
  UNIQUE KEY `us_aadhaar_2` (`us_aadhaar`),
  KEY `us_roid` (`us_roid`),
  KEY `us_coid` (`us_coid`),
  KEY `idx_us_usertype` (`us_usertype`),
  KEY `idx_us_city` (`us_city`),
  KEY `idx_us_state` (`us_state`),
  CONSTRAINT `ususer_ibfk_3` FOREIGN KEY (`us_roid`) REFERENCES `fnXfunction` (`fn_fnid`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `ususer_ibfk_4` FOREIGN KEY (`us_coid`) REFERENCES `coCompany` (`co_coid`) ON DELETE SET NULL ON UPDATE CASCADE
