DROP TABLE IF EXISTS `usXuser`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `usXuser` (
  `us_usid` varchar(15) NOT NULL DEFAULT '' COMMENT 'User ID',
  `us_email` varchar(120) NOT NULL DEFAULT '' COMMENT 'Email',
  `us_usname` varchar(100) NOT NULL DEFAULT '' COMMENT 'User Name',
  `us_title` varchar(100) DEFAULT '' COMMENT 'Job Title',
  `us_phone` varchar(30) DEFAULT '' COMMENT 'Phone',
  `us_admin` tinyint NOT NULL DEFAULT '0' COMMENT 'Is Application Administrator?',
  `us_security` tinyint NOT NULL DEFAULT '0' COMMENT 'Is Security Administrator?',
  `us_limit` decimal(18,2) DEFAULT NULL COMMENT 'Authorization Limit',
  `us_rmrks` longtext COMMENT 'Remarks',
  `us_active` tinyint NOT NULL DEFAULT '0' COMMENT 'Active?',
  `us_edtm` datetime DEFAULT NULL COMMENT 'Entered On',
  `us_eby` varchar(30) DEFAULT '' COMMENT 'Entered By',
  `us_mdtm` datetime DEFAULT NULL COMMENT 'Modified On',
  `us_mby` varchar(30) DEFAULT '' COMMENT 'Modified By',
  `us_cdtm` datetime DEFAULT NULL COMMENT 'Closed On',
  `us_cby` varchar(30) DEFAULT '' COMMENT 'Closed By',
  `us_fname` varchar(50) DEFAULT '' COMMENT 'First Name',
  `us_lname` varchar(50) DEFAULT '' COMMENT 'Last Name',
  `us_aadhaar` varchar(12) DEFAULT '' COMMENT 'Aadhaar Number',
  `us_pan` varchar(10) DEFAULT '' COMMENT 'PAN Number',
  `us_addr1` varchar(200) DEFAULT '' COMMENT 'Address Line 1',
  `us_city` varchar(50) DEFAULT '' COMMENT 'City',
  `us_state` varchar(50) DEFAULT '' COMMENT 'State',
  `us_pin` varchar(10) DEFAULT '' COMMENT 'PIN Code',
  `us_usertype` varchar(20) DEFAULT NULL COMMENT 'User Type',
  `us_roid` varchar(10) DEFAULT NULL COMMENT 'Role ID',
  `us_coid` varchar(10) DEFAULT NULL COMMENT 'Company ID',
  `us_appadmin` tinyint NOT NULL DEFAULT '0' COMMENT 'Application Administrator',
  `us_photo` varchar(255) DEFAULT NULL COMMENT 'Employee Photo Path',
  PRIMARY KEY (`us_usid`),
  UNIQUE KEY `us_email` (`us_email`),
  UNIQUE KEY `us_user_us_email` (`us_email`),
  UNIQUE KEY `us_email_2` (`us_email`),
  UNIQUE KEY `us_xuser_us_email` (`us_email`),
  UNIQUE KEY `us_email_3` (`us_email`),
  UNIQUE KEY `us_email_4` (`us_email`),
  UNIQUE KEY `us_email_5` (`us_email`),
  UNIQUE KEY `us_email_6` (`us_email`),
  UNIQUE KEY `us_email_7` (`us_email`),
  UNIQUE KEY `us_email_8` (`us_email`),
  UNIQUE KEY `us_email_9` (`us_email`),
  UNIQUE KEY `us_email_10` (`us_email`),
  UNIQUE KEY `us_email_11` (`us_email`),
  UNIQUE KEY `us_email_12` (`us_email`),
  UNIQUE KEY `us_email_13` (`us_email`),
  UNIQUE KEY `us_email_14` (`us_email`),
  UNIQUE KEY `us_email_15` (`us_email`),
  UNIQUE KEY `us_email_16` (`us_email`),
  UNIQUE KEY `us_email_17` (`us_email`),
  UNIQUE KEY `us_email_18` (`us_email`),
  UNIQUE KEY `us_email_19` (`us_email`),
  UNIQUE KEY `us_user_us_phone` (`us_phone`),
  KEY `us_roid` (`us_roid`),
  KEY `idx_user_phone` (`us_phone`),
  KEY `idx_us_usertype` (`us_usertype`),
  KEY `idx_us_city` (`us_city`),
  KEY `idx_us_state` (`us_state`),
  CONSTRAINT `usxuser_ibfk_1` FOREIGN KEY (`us_roid`) REFERENCES `fnXfunction` (`fn_fnid`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
